{
  "mcpServers": {
    "web-search": {
      "command": "node",
      "args": ["/root/web-search-mcp/dist/index.js"],
      "env": {
        "BROWSER_HEADLESS": "true"
      }
    },
    "chromium": {
      "command": "npx",
      "args": [
        "-y",
        "chrome-devtools-mcp@1.6.0",
        "--headless",
        "--isolated",
        "--executablePath",
        "/usr/bin/chromium",
        "--chromeArg=--no-sandbox",
        "--chromeArg=--disable-gpu",
        "--no-usage-statistics",
        "--allow-unrestricted-paths"
      ]
    },
    "firefox": {
      "command": "npx",
      "args": [
        "-y",
        "@playwright/mcp@0.0.78",
        "--browser",
        "firefox",
        "--headless",
        "--isolated",
        "--allow-unrestricted-file-access",
        "--output-dir",
        "/workspace/.playwright-mcp"
      ]
    }
  }
}

